def build_saml_request(destination_url, user_name, email, relay_state=""):
    issue_instant = datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ")
    request_id = "_" + str(uuid.uuid4())

    saml_xml = (
        '<?xml version="1.0" encoding="UTF-8"?>'
        '<samlp:AuthnRequest '
        'xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol" '
        'xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion" '
        f'ID="{request_id}" '
        'Version="2.0" '
        f'IssueInstant="{issue_instant}" '
        f'Destination="{destination_url}" '
        'ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST" '
        'AssertionConsumerServiceURL="http://localhost:5000/acs">'
        '<saml:Issuer>http://localhost:5000/sp</saml:Issuer>'
        '<saml:Subject>'
        f'<saml:NameID>{user_name}</saml:NameID>'
        '<saml:SubjectConfirmation '
        'Method="urn:oasis:names:tc:SAML:2.0:cm:bearer"/>'
        '</saml:Subject>'
        '<samlp:NameIDPolicy '
        'AllowCreate="true" '
        'Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"/>'
        '<samlp:RequestedAuthnContext Comparison="exact">'
        '<saml:AuthnContextClassRef>'
        'urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport'
        '</saml:AuthnContextClassRef>'
        '</samlp:RequestedAuthnContext>'
        '<saml:AttributeStatement>'
        '<saml:Attribute Name="email">'
        f'<saml:AttributeValue>{email}</saml:AttributeValue>'
        '</saml:Attribute>'
        '</saml:AttributeStatement>'
        '</samlp:AuthnRequest>'
    )

    encoded_request = base64.b64encode(saml_xml.encode("utf-8")).decode("utf-8")
    return encoded_request, relay_state

@app.route("/login", methods=["GET", "POST"])
def login():
    destination = request.values.get("destination", "")
    user_name = request.values.get("user_name", "")
    email = request.values.get("email", "")
    relay_state = request.values.get("relay_state", "")

    saml_request, relay_state = build_saml_request(destination, user_name, email, relay_state)
    html = HTML_TEMPLATE.format(
        destination=destination,
        saml_request=saml_request,
        relay_state=relay_state
    )
    return Response(html, mimetype="text/html")

